  1	import React, { useState } from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import { ProjectRequestModel } from '@kubevirt-ui/kubevirt-api/console';
  5	import { documentationURL } from '@kubevirt-utils/constants/documentation';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import { isEmpty } from '@kubevirt-utils/utils/utils';
  8	import { k8sCreate, K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  Button,
 11	  ButtonVariant,
 12	  Form,
 13	  FormGroup,
 14	  Popover,
 15	  Text,
 16	  TextInput,
 17	} from '@patternfly/react-core';
 18	import { HelpIcon } from '@patternfly/react-icons';
 19	
 20	import ExternalLink from '../ExternalLink/ExternalLink';
 21	import TabModal from '../TabModal/TabModal';
 22	
 23	type CreateProjectModalProps = {
 24	  createdProject?: (value: K8sResourceCommon) => void;
 25	  isOpen: boolean;
 26	  onClose: () => void;
 27	};
 28	
 29	const CreateProjectModal: React.FC<CreateProjectModalProps> = ({
 30	  createdProject,
 31	  isOpen,
 32	  onClose,
 33	}) => {
 34	  const { t } = useKubevirtTranslation();
 35	  const [name, setName] = useState<string>();
 36	  const [description, setDescription] = useState<string>();
 37	  const [displayName, setDisplayName] = useState<string>();
 38	
 39	  return (
 40	    <TabModal<K8sResourceCommon & { description: string; displayName: string }>
 41	      onSubmit={(data) =>
 42	        k8sCreate({
 43	          data,
 44	          model: ProjectRequestModel,
 45	        }).then((value) => createdProject?.(value))
 46	      }
 47	      headerText={t('Create project')}
 48	      isDisabled={isEmpty(name)}
 49	      isOpen={isOpen}
 50	      obj={{ description, displayName, metadata: { name } }}
 51	      onClose={onClose}
 52	      submitBtnText={t('Create')}
 53	    >
 54	      <Text>
 55	        {t('An OpenShift project is an alternative representation of a Kubernetes namespace.')}
 56	      </Text>
 57	      <br />
 58	      <ExternalLink href={documentationURL.PROJECTS}>
 59	        {t('Learn more about working with projects')}
 60	      </ExternalLink>
 61	      <br />
 62	      <br />
 63	      <Form>
 64	        <FormGroup
 65	          labelHelp={
 66	            <Popover
 67	              bodyContent={
 68	                <Trans ns="plugin__kubevirt-plugin" t={t}>
 69	                  A Project name must consist of lower case alphanumeric characters or &apos;, and
 70	                  must start and end with an alphanumeric character (e.g. &apos;my-name&apos; or
 71	                  &apos;123-abc&apos;). You must create a Namespace to be able to create projects
 72	                  that begin with &apos;openshift-&apos;, &apos;kubernetes-&apos;, or
 73	                  &apos;kube-&apos;.
 74	                </Trans>
 75	              }
 76	            >
 77	              <Button variant={ButtonVariant.plain}>
 78	                <HelpIcon />
 79	              </Button>
 80	            </Popover>
 81	          }
 82	          fieldId="project-name"
 83	          isRequired
 84	          label={t('Name')}
 85	        >
 86	          <TextInput
 87	            id="project-name"
 88	            isRequired
 89	            name="project-name"
 90	            onChange={(_event, value) => setName(value)}
 91	            type="text"
 92	            value={name}
 93	          />
 94	        </FormGroup>
 95	        <FormGroup fieldId="display-name" label="Display name">
 96	          <TextInput
 97	            id="display-name"
 98	            name="display-name"
 99	            onChange={(_event, value) => setDisplayName(value)}
100	            type="text"
101	            value={displayName}
102	          />
103	        </FormGroup>
104	        <FormGroup fieldId="description" label="Description">
105	          <TextInput
106	            id="description"
107	            name="description"
108	            onChange={(_event, value) => setDescription(value)}
109	            type="text"
110	            value={description}
111	          />
112	        </FormGroup>
113	      </Form>
114	    </TabModal>
115	  );
116	};
117	
118	export default CreateProjectModal;

